// ❌ BAD - using attribute syntax to pass a dynamic object causes string coercion
<app-order-summary status="{{ order.status }}" />

// ✅ GOOD - property binding passes the real typed value to the @Input
<app-order-summary [status]="order.status" />

// All four binding types together:
// <h2>{{ order.customerName }}</h2>          -- interpolation
// <input [disabled]="isSubmitting" />        -- property binding
// <button (click)="placeOrder()">Buy</button>  -- event binding
// <input [(ngModel)]="promoCode" />           -- two-way binding

// ❌ BAD - Promise fires immediately and cannot be cancelled, even if user navigates away
constructor(private http: HttpClient) {
  fetch('/api/invoices').then(r => r.json()).then(data => this.invoices = data);
}

// ✅ GOOD - Observable cancels the HTTP request when the component is destroyed
export class InvoiceListComponent {
  invoices$ = inject(HttpClient).get<Invoice[]>('/api/invoices');
  // template: *ngFor="let inv of invoices$ | async"
  // async pipe auto-cancels on destroy - no memory leak
}

// ❌ BAD - child mutates the input object directly, breaking unidirectional data flow
export class ShippingFormComponent {
  @Input() order!: Order;
  confirmShipment() { this.order.status = 'shipped'; } // mutates parent's object
}

// ✅ GOOD - child emits an event, parent owns the state update
import { input, output } from '@angular/core';
export class ShippingFormComponent {
  order = input.required<Order>();      // signal input - reactive
  shipped = output<Order>();            // signal output
  confirmShipment() {
    this.shipped.emit({ ...this.order(), status: 'shipped' });
  }
}

// ❌ BAD - template-driven form for a checkout wizard with dynamic address fields
// Model is implicit, hard to test, no typed values, dynamic rows are painful
<form #checkoutForm="ngForm">
  <input name="email" ngModel required />
</form>

// ✅ GOOD - reactive form with typed FormGroup
export class CheckoutComponent {
  checkoutForm = new FormGroup({
    email: new FormControl('', { validators: [Validators.required, Validators.email] }),
    shippingAddresses: new FormArray([])
  });
  addAddress() {
    this.checkoutForm.controls.shippingAddresses.push(
      new FormControl('', Validators.required)
    );
  }
}

// ❌ BAD - nested subscribe creates unmanaged inner subscriptions and cannot cancel
this.searchControl.valueChanges.subscribe(query => {
  this.productService.search(query).subscribe(results => this.results = results);
});

// ✅ GOOD - switchMap flattens and cancels previous search on each new keystroke
results$ = this.searchControl.valueChanges.pipe(
  debounceTime(300),
  distinctUntilChanged(),
  filter(q => q.length > 2),
  switchMap(q => this.productService.search(q)),
  catchError(() => of([]))
);

// ❌ BAD - subscription never cancelled, lives until the app closes
export class LivePriceComponent implements OnInit {
  ngOnInit() {
    this.stockService.priceUpdates$.subscribe(price => this.price = price);
  }
}

// ✅ GOOD - takeUntilDestroyed auto-cancels when the component is destroyed
import { takeUntilDestroyed } from '@angular/core/rxjs-interop';
export class LivePriceComponent {
  private destroyRef = inject(DestroyRef);
  constructor() {
    this.stockService.priceUpdates$
      .pipe(takeUntilDestroyed(this.destroyRef))
      .subscribe(price => this.price = price);
  }
}

// ❌ BAD - exposing the Subject directly lets any component call .next() and corrupt shared state
@Injectable({ providedIn: 'root' })
export class NotificationService {
  public notifications$ = new BehaviorSubject<Notification[]>([]);
}

// ✅ GOOD - private Subject, public read-only Observable
@Injectable({ providedIn: 'root' })
export class NotificationService {
  private notificationsSource = new BehaviorSubject<Notification[]>([]);
  readonly notifications$ = this.notificationsSource.asObservable();
  addNotification(n: Notification) {
    this.notificationsSource.next([...this.notificationsSource.value, n]);
  }
}

// ❌ BAD - cold Observable used twice triggers two HTTP requests
export class ProductPageComponent {
  products$ = this.http.get<Product[]>('/api/products');
  // template: *ngIf="products$ | async as products" ... (products$ | async)?.length
  // Two async pipes = two GET requests!
}

// ✅ GOOD - shareReplay(1) makes it hot and caches the result
export class ProductPageComponent {
  products$ = this.http.get<Product[]>('/api/products').pipe(
    shareReplay(1) // one request, result cached for late subscribers
  );
}

// ❌ BAD - component has Zone.js overhead and needs manual ngOnChanges for derived values
export class OrderSummaryComponent implements OnChanges {
  @Input() items: OrderItem[] = [];
  total = 0;
  ngOnChanges() { this.total = this.items.reduce((s, i) => s + i.price, 0); }
}

// ✅ GOOD - signal input with computed() - reactive, no ngOnChanges needed
import { input, computed } from '@angular/core';
export class OrderSummaryComponent {
  items = input<OrderItem[]>([]);
  total = computed(() => this.items().reduce((s, i) => s + i.price, 0));
  // total() updates automatically whenever items() changes
}
